INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('09-doanh-nghiep-pmap',2,9,'DOANH NGHIỆP P.M.A.P','Doanh nghiep P.M.A.P',9,'draft','2026-06-20T11:06:29Z','2026-06-20T11:06:29Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('57cb178d-54a7-4c75-a6b5-f5d913af5d6f','09-doanh-nghiep-pmap',NULL,2,'9.1 Giới thiệu về Empire Flywheel','91-gioi-thieu-ve-empire-flywheel',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('777ac584-a00a-4506-a157-a6a76e637306','57cb178d-54a7-4c75-a6b5-f5d913af5d6f',0,'text','Empire Flywheel là mô hình vòng lặp tăng trưởng đặc thù cho phòng khám nha khoa, nơi các tài sản thương hiệu (case thực tế, content, uy tín bác sĩ, trải nghiệm bệnh nhân, review, referral…) được tích lũy và tái sử dụng để tạo động lượng gia tăng liên tục.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('38ae0ad4-bb5a-4158-9ea4-fe20c791c449','57cb178d-54a7-4c75-a6b5-f5d913af5d6f',1,'text','Khác với phễu (funnel) truyền thống chỉ đốt ngân sách để mua lead, Flywheel thu năng lượng từ chính bệnh nhân đã chữa trị để giảm CAC (Customer Acquisition Cost - chi phí thu hút / có được một khách hàng mới) và tăng giá trị theo thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5dc59c9c-7f04-4c81-8b5a-3ed352f0848a','09-doanh-nghiep-pmap',NULL,2,'9.2 Flywheel là gì trong Dental Empire OS?','92-flywheel-la-gi-trong-dental-empire-os',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('73deb78a-80a6-40ed-b837-3afb8e9f6963','5dc59c9c-7f04-4c81-8b5a-3ed352f0848a',2,'image',NULL,'book/09-doanh-nghiep-pmap/fca6ee82-85d9-4ace-9b60-2ce7ccaa44f3-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('45571d3f-b273-4156-a190-f6730765444a','5dc59c9c-7f04-4c81-8b5a-3ed352f0848a',3,'text','Empire Flywheel là hệ thống vòng lặp gồm các lớp nối tiếp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0507ab05-88be-4746-b641-66ccf0a7fed4','5dc59c9c-7f04-4c81-8b5a-3ed352f0848a',4,'text','Personal Brand → Media & Content → Clinic System -> Trust Assets → Search / Authority → Patient (booking & treatment) → Review → Referral → Content mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ebbfb11-3bde-43d6-be29-d5b5250528b2','5dc59c9c-7f04-4c81-8b5a-3ed352f0848a',5,'text','Mỗi vòng quay tích luỹ thêm nhận diện, bằng chứng và uy tín, từ đó tăng khả năng xuất hiện, chuyển đổi và giới thiệu bệnh nhân mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('61f385a0-3dea-4c73-bb33-71b005cbd235','09-doanh-nghiep-pmap',NULL,2,'9.3 Vì sao tăng trưởng phải là vòng quay, không phải đường thẳng?','93-vi-sao-tang-truong-phai-la-vong-quay-khong-phai-uong-thang',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3ee71712-2ba0-4d72-b77d-4ae513383892','61f385a0-3dea-4c73-bb33-71b005cbd235',6,'text','- Tính bản chất ngành nha khoa: quyết định của bệnh nhân phụ thuộc vào niềm tin, bằng chứng và uy tín bác sĩ hơn là quảng cáo đơn thuần. - Phễu (Funnel) là mô hình một chiều: chi tiền để có traffic → leads → chuyển đổi; khi dừng chi tiền, nguồn khách cạn.- Flywheel tái tạo năng lượng: mỗi bệnh nhân tốt trở thành nguồn nội lực (review, referral, case) để nuôi vòng quay, giúp chi phí marketing giảm dần và tăng hiệu quả theo thời gian.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('59885ed9-8067-4e21-9fee-3b86b9d106a4','09-doanh-nghiep-pmap',NULL,2,'9.4 Lực đẩy đầu tiên của vòng quay','94-luc-ay-au-tien-cua-vong-quay',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('37e138ee-9665-4f91-85a9-2613c50cab15','59885ed9-8067-4e21-9fee-3b86b9d106a4',7,'text','Khởi động Flywheel cần hai trụ cột chính:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d716eaf6-4ee2-4eaf-86e7-2e2bbf8bc425','59885ed9-8067-4e21-9fee-3b86b9d106a4',8,'text','- **Content và Case** thực tế chất lượng: video trước - sau, case study, nội dung giáo dục, testimonial.- **Personal Brand của bác sĩ/founder**: uy tín cá nhân giúp rút ngắn niềm tin ban đầu và tăng tỉ lệ chuyển đổi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96f1cc88-7d78-446c-b80a-f269012ee708','59885ed9-8067-4e21-9fee-3b86b9d106a4',9,'text','Khi hai yếu tố này có, chúng tạo traffic và niềm tin ban đầu để kích hoạt chu trình booking → điều trị → review.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('16af4bc6-28f6-4f1f-bcea-aff9a88a3be2','09-doanh-nghiep-pmap',NULL,2,'9.5 Những điểm chạm làm vòng quay mạnh lên','95-nhung-iem-cham-lam-vong-quay-manh-len',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('51498bd0-d1b2-464b-96ec-d382299e1a2f','16af4bc6-28f6-4f1f-bcea-aff9a88a3be2',10,'text','- Content: video case, clip giáo dục, testimonial - cung cấp bằng chứng và tạo nhu cầu.- Media Network: phân phối trên TikTok, YouTube, Facebook, Zalo và website để tối đa hóa reach và repeat exposure.- Trust Assets: hồ sơ bác sĩ, hồ sơ case, chứng nhận, before‑after gallery - tăng authority khi khách tìm kiểm. - Search & Local SEO (Google Map, AI Search): khi khách chủ động tìm, xuất hiện authority giúp tăng chuyển đổi. - Patient Experience: kịch bản tư vấn, quy trình điều trị rõ ràng, chăm sóc sau - chuyển trải nghiệm thành review & referral.- Referral System: quy trình xin giới thiệu, chương trình cảm ơn, tracking nguồn giới thiệu - biến khách hài lòng thành kênh khách mới chi phí thấp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('69450a3b-120b-4237-85fe-416ce12854e9','09-doanh-nghiep-pmap',NULL,2,'9.6 Khi nào flywheel bị chậm hoặc gãy?','96-khi-nao-flywheel-bi-cham-hoac-gay',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c3b55e82-28b8-4f2e-89fc-7a6a13cd18e1','69450a3b-120b-4237-85fe-416ce12854e9',11,'text','Flywheel mất động lực khi một hoặc nhiều mắt xích bị yếu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('553b8b18-2f8b-45f2-9b68-fc744caeba26','69450a3b-120b-4237-85fe-416ce12854e9',12,'text','- Content nghèo hoặc thiếu case thật; không có vật liệu để nuôi media.- Personal Brand mờ, bác sĩ không hiện diện hoặc không có bằng chứng chuyên môn rõ ràng.- Trải nghiệm bệnh nhân kém: tỉ lệ hoàn tất điều trị thấp, nhiều phàn nàn, không xin được review.- Thiếu quy trình thu review/referral: không có SOP để biến bệnh nhân hài lòng thành review/case/testimonial.- Kênh media hoặc SEO yếu: dù có content, nhưng không phân phối tốt hoặc không xuất hiện khi người tìm kiếm tra cứu.- Vận hành lỏng lẻo: không có OS, KPI, vai trò rõ ràng - khiến việc duy trì vòng quay phụ thuộc cá nhân, dễ đứt gãy',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7d05e835-54f6-49da-af1a-dfc79773a8e0','09-doanh-nghiep-pmap',NULL,2,'9.7 Khi Flywheel vận hành tốt thì sao?','97-khi-flywheel-van-hanh-tot-thi-sao',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ebf8e42a-73e1-423a-8a5c-a2259ecaa7a4','7d05e835-54f6-49da-af1a-dfc79773a8e0',13,'image',NULL,'book/09-doanh-nghiep-pmap/88c03f60-fd85-49c1-868d-c8d774b2449c-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c62a68c8-d6fa-40d3-b7a8-7dd30cc1bed1','7d05e835-54f6-49da-af1a-dfc79773a8e0',14,'text','Khi "bánh xe xoay tròn" hệ thống sẽ tự tạo ra một chuỗi tăng trưởng liên tục:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf6b06b9-f6f0-438b-b94f-81e8a0b024b9','7d05e835-54f6-49da-af1a-dfc79773a8e0',15,'text','- Review làm tăng **authority** (uy tín).- Authority làm tăng **conversion** (tỷ lệ chuyển đổi).- Conversion tạo thêm **patients** (bệnh nhân).- Bệnh nhân hài lòng tạo **referral** (giới thiệu).- Referral mang về khách chất lượng hơn.- **Community** (cộng đồng) giúp tăng **retention** (tỷ lệ quay lại).- Còn **products / education** (sản phẩm / giáo dục) tạo thêm nội dung và doanh thu. - Toàn bộ kết quả này quay lại nuôi **Personal Brand** (thương hiệu cá nhân) và **Media Network** (hệ thống truyền thông), khiến vòng quay ngày càng mạnh hơn theo thời gian.',NULL,NULL,NULL,NULL,NULL);
